import { supabase } from './supabase'

export interface Company {
  id: string
  name: string
  businessNumber: string
  businessLicenseReceived: boolean
  contact: string
  phone: string
  email: string
  products: string
  quantity: string
  dueDate: string
  address: string
  deliveryCondition: string
  budget: string
  purpose: string
  taxInvoiceType: '필요(영수)' | '필요(청구)' | '불필요' | ''
  estimateDelivered: boolean
  status: string
  createdAt: string
  notes: string
  progressChecklist?: {
    paymentConfirmed: boolean
    manufacturerOrdered: boolean
  }
  estimatePrice?: string
  finalPrice?: string
}

export interface OutboundCompany {
  id: string
  name: string
  contact: string
  phone: string
  email: string
  industry: string
  status: '미연락' | '연락중' | '관심있음' | '거절' | '완료'
  notes: string
  createdAt: string
  lastContactDate?: string
  sourceType: 'completed' | 'pending'
}

// Supabase row → Company
export function rowToCompany(row: any): Company {
  return {
    id: String(row.id),
    name: row.name || '',
    businessNumber: row.business_number || '',
    businessLicenseReceived: !!row.business_license_received,
    contact: row.contact || '',
    phone: row.phone || '',
    email: row.email || '',
    products: row.products || '',
    quantity: row.quantity || '',
    dueDate: row.due_date || '',
    address: row.address || '',
    deliveryCondition: row.delivery_condition || '',
    budget: row.budget || '',
    purpose: row.purpose || '',
    taxInvoiceType: row.tax_invoice_type || '',
    estimateDelivered: !!row.estimate_delivered,
    status: row.status || '문의접수',
    createdAt: row.created_at || '',
    notes: row.notes || '',
    progressChecklist: row.progress_checklist || {
      paymentConfirmed: false,
      manufacturerOrdered: false,
    },
    estimatePrice: row.estimate_price || '',
    finalPrice: row.final_price || '',
  }
}

// Company → Supabase row (id 제외)
export function companyToRow(c: Partial<Company>): any {
  const row: any = {}
  if (c.name !== undefined) row.name = c.name
  if (c.businessNumber !== undefined) row.business_number = c.businessNumber
  if (c.businessLicenseReceived !== undefined) row.business_license_received = c.businessLicenseReceived
  if (c.contact !== undefined) row.contact = c.contact
  if (c.phone !== undefined) row.phone = c.phone
  if (c.email !== undefined) row.email = c.email
  if (c.products !== undefined) row.products = c.products
  if (c.quantity !== undefined) row.quantity = c.quantity
  if (c.dueDate !== undefined) row.due_date = c.dueDate
  if (c.address !== undefined) row.address = c.address
  if (c.deliveryCondition !== undefined) row.delivery_condition = c.deliveryCondition
  if (c.budget !== undefined) row.budget = c.budget
  if (c.purpose !== undefined) row.purpose = c.purpose
  if (c.taxInvoiceType !== undefined) row.tax_invoice_type = c.taxInvoiceType
  if (c.estimateDelivered !== undefined) row.estimate_delivered = c.estimateDelivered
  if (c.status !== undefined) row.status = c.status
  if (c.createdAt !== undefined) row.created_at = c.createdAt
  if (c.notes !== undefined) row.notes = c.notes
  if (c.progressChecklist !== undefined) row.progress_checklist = c.progressChecklist
  if (c.estimatePrice !== undefined) row.estimate_price = c.estimatePrice
  if (c.finalPrice !== undefined) row.final_price = c.finalPrice
  return row
}

export function rowToOutbound(row: any): OutboundCompany {
  return {
    id: String(row.id),
    name: row.name || '',
    contact: row.contact || '',
    phone: row.phone || '',
    email: row.email || '',
    industry: row.industry || '',
    status: (row.status || '미연락') as OutboundCompany['status'],
    notes: row.notes || '',
    createdAt: row.created_at || '',
    lastContactDate: row.last_contact_date || '',
    sourceType: (row.source_type || 'pending') as OutboundCompany['sourceType'],
  }
}

export function outboundToRow(o: Partial<OutboundCompany>): any {
  const row: any = {}
  if (o.name !== undefined) row.name = o.name
  if (o.contact !== undefined) row.contact = o.contact
  if (o.phone !== undefined) row.phone = o.phone
  if (o.email !== undefined) row.email = o.email
  if (o.industry !== undefined) row.industry = o.industry
  if (o.status !== undefined) row.status = o.status
  if (o.notes !== undefined) row.notes = o.notes
  if (o.createdAt !== undefined) row.created_at = o.createdAt
  if (o.lastContactDate !== undefined) row.last_contact_date = o.lastContactDate
  if (o.sourceType !== undefined) row.source_type = o.sourceType
  return row
}

// ====== 진행업체 CRUD ======
export async function fetchCompanies(): Promise<Company[]> {
  const { data, error } = await supabase
    .from('b2b_companies')
    .select('*')
    .order('inserted_at', { ascending: false })
  if (error) {
    console.error('Failed to fetch companies:', error)
    return []
  }
  return (data || []).map(rowToCompany)
}

export async function insertCompany(c: Partial<Company>): Promise<Company | null> {
  const { data, error } = await supabase
    .from('b2b_companies')
    .insert(companyToRow(c))
    .select()
    .single()
  if (error) {
    console.error('Failed to insert company:', error)
    return null
  }
  return rowToCompany(data)
}

export async function updateCompanyRow(id: string, updates: Partial<Company>): Promise<boolean> {
  const { error } = await supabase
    .from('b2b_companies')
    .update(companyToRow(updates))
    .eq('id', Number(id))
  if (error) {
    console.error('Failed to update company:', error)
    return false
  }
  return true
}

export async function deleteCompanyRow(id: string): Promise<boolean> {
  const { error } = await supabase
    .from('b2b_companies')
    .delete()
    .eq('id', Number(id))
  if (error) {
    console.error('Failed to delete company:', error)
    return false
  }
  return true
}

// ====== 아웃바운딩 CRUD ======
export async function fetchOutbound(): Promise<OutboundCompany[]> {
  const { data, error } = await supabase
    .from('b2b_outbound')
    .select('*')
    .order('inserted_at', { ascending: false })
  if (error) {
    console.error('Failed to fetch outbound:', error)
    return []
  }
  return (data || []).map(rowToOutbound)
}

export async function insertOutbound(o: Partial<OutboundCompany>): Promise<OutboundCompany | null> {
  const { data, error } = await supabase
    .from('b2b_outbound')
    .insert(outboundToRow(o))
    .select()
    .single()
  if (error) {
    console.error('Failed to insert outbound:', error)
    return null
  }
  return rowToOutbound(data)
}

export async function updateOutboundRow(id: string, updates: Partial<OutboundCompany>): Promise<boolean> {
  const { error } = await supabase
    .from('b2b_outbound')
    .update(outboundToRow(updates))
    .eq('id', Number(id))
  if (error) {
    console.error('Failed to update outbound:', error)
    return false
  }
  return true
}

export async function deleteOutboundRow(id: string): Promise<boolean> {
  const { error } = await supabase
    .from('b2b_outbound')
    .delete()
    .eq('id', Number(id))
  if (error) {
    console.error('Failed to delete outbound:', error)
    return false
  }
  return true
}

export async function existsOutboundByPhone(phone: string): Promise<boolean> {
  if (!phone) return false
  const { data, error } = await supabase
    .from('b2b_outbound')
    .select('id')
    .eq('phone', phone)
    .limit(1)
  if (error) return false
  return (data || []).length > 0
}

// ====== localStorage 자동 마이그레이션 ======
export async function migrateLocalStorageIfNeeded() {
  if (typeof window === 'undefined') return

  // 진행업체 마이그레이션
  try {
    const localCompanies = localStorage.getItem('b2b-companies')
    if (localCompanies) {
      const parsed = JSON.parse(localCompanies)
      if (Array.isArray(parsed) && parsed.length > 0) {
        // Supabase에 데이터가 있는지 확인
        const { data: existing } = await supabase
          .from('b2b_companies')
          .select('id')
          .limit(1)
        if (!existing || existing.length === 0) {
          // 마이그레이션 진행
          const rows = parsed.map((c: any) => companyToRow({
            ...c,
            businessLicenseReceived: c.businessLicenseReceived ?? false,
            deliveryCondition: c.deliveryCondition || '',
            taxInvoiceType: c.taxInvoiceType || '',
            estimateDelivered: c.estimateDelivered ?? false,
            progressChecklist: c.progressChecklist || { paymentConfirmed: false, manufacturerOrdered: false },
            estimatePrice: c.estimatePrice || '',
            finalPrice: c.finalPrice || '',
          }))
          await supabase.from('b2b_companies').insert(rows)
        }
        // 마이그레이션 후 localStorage 백업 후 삭제
        localStorage.setItem('b2b-companies-backup', localCompanies)
        localStorage.removeItem('b2b-companies')
      }
    }
  } catch (e) {
    console.error('Failed to migrate companies:', e)
  }

  // 아웃바운딩 마이그레이션
  try {
    const localOutbound = localStorage.getItem('b2b-outbound')
    if (localOutbound) {
      const parsed = JSON.parse(localOutbound)
      if (Array.isArray(parsed) && parsed.length > 0) {
        const { data: existing } = await supabase
          .from('b2b_outbound')
          .select('id')
          .limit(1)
        if (!existing || existing.length === 0) {
          const rows = parsed.map((o: any) => outboundToRow({
            ...o,
            sourceType: o.sourceType || 'pending',
          }))
          await supabase.from('b2b_outbound').insert(rows)
        }
        localStorage.setItem('b2b-outbound-backup', localOutbound)
        localStorage.removeItem('b2b-outbound')
      }
    }
  } catch (e) {
    console.error('Failed to migrate outbound:', e)
  }
}
